public async Task PurchaseTicketsAsync(int eventId, int quantity)
{
    using var context = new ApplicationDbContext();
    var @event = await context.Events.FindAsync(eventId);

    if (@event == null || @event.RemainingSeats < quantity)
        throw new Exception("Event not found or no more seats available.");

    var purchase = new Purchase { Quantity = quantity, EventId = eventId, PurchaseTime = DateTimeOffset.UtcNow };
    context.Entry(@event).State = EntityState.Modified;
    @event.RemainingSeats -= quantity;
    await context.SaveChangesAsync();
}